'use strict';

/**
* The mathematical constant `π`.
*
* @module @stdlib/constants-float16-pi
* @type {number}
*
* @example
* import FLOAT16_PI from '@stdlib/constants-float16-pi';
* // returns 3.140625
*/

/**
* The mathematical constant `π`.
*
* @constant
* @type {number}
* @default 3.140625
* @see [Wikipedia]{@link https://en.wikipedia.org/wiki/Pi}
*/
var FLOAT16_PI = 3.140625;


// EXPORTS //

export default FLOAT16_PI;
